import{_ as s,o as r,c as a,a6 as t,gU as o,gV as i,gW as e,gX as g,gY as n,gZ as c,ey as _,g_ as l,gL as m,g$ as d,h0 as h,jc as f,jd as b,je as j,jf as u,jg as x,jh as k,ji as P,jj as T,jk as S}from"./chunks/framework.UYVGz2W_.js";const E=JSON.parse('{"title":"公開","description":"","frontmatter":{},"headers":[],"relativePath":"ja/publish/index.md","filePath":"ja/publish/index.md"}'),$={name:"ja/publish/index.md"};function v(A,p,V,D,N,B){return r(),a("div",null,[...p[0]||(p[0]=[t('<h1 id="公開" tabindex="-1">公開 <a class="header-anchor" href="#公開" aria-label="Permalink to “公開”">​</a></h1><h2 id="コンセプトの公開" tabindex="-1">コンセプトの公開 <a class="header-anchor" href="#コンセプトの公開" aria-label="Permalink to “コンセプトの公開”">​</a></h2><p><strong>コンセプト</strong>を公開するには、プロジェクトナビゲーションメニューから<strong>コンセプト</strong>ページに移動します。</p><p><img src="'+o+'" alt="コンセプトメニュー"></p><p>コンセプトをアップロードするには、「<strong>コンセプトへの新しい参照を追加</strong>」ボタンをクリックします。1つまたは複数のコンセプトを同時にアップロードできます。</p><p><img src="'+i+'" alt="コンセプトの空ページ"></p><p>アップロードが完了すると、プレビューが生成され、コンセプトページから表示できるようになります。</p><p><img src="'+e+'" alt="コンセプトの入力ページ"></p><p>サムネイルをクリックすると、コンセプトの拡大プレビューが表示されます。ステータスをクリックすると、右側に<strong>コメントパネル</strong>が開きます。</p><p>コメントパネルが開いている場合、次の2つのオプションがあります。</p><ol><li>コンセプトを既存のアセットにリンクしたり、既存のリンクを削除したりすることができます。</li><li>コンセプトにコメントを追加したり、ステータスを変更したりすることができます。</li></ol><p><strong>コンセプト</strong>は1バージョンのみにしておくのが望ましいです。コンセプトが承認されず、さらに変更が必要な場合は、そのコンセプトをバージョンアップした方が良いでしょう。</p><p><img src="'+g+'" alt="コンセプトオプション"></p><h2 id="コンセプトとアセットのリンク" tabindex="-1">コンセプトとアセットのリンク <a class="header-anchor" href="#コンセプトとアセットのリンク" aria-label="Permalink to “コンセプトとアセットのリンク”">​</a></h2><p>コンセプトをアップロードすると、アセットにリンクすることができます。</p><p>リンクされたアセットの名前は、コンセプトのサムネイルの下、ステータスの上に表示されます。アセットがリンクされていない場合は、このエリアは空白になります。</p><p>コンセプトのステータスをクリックすると、右側にコメントパネルが開きます。</p><p><img src="'+n+'" alt="コンセプトコメントパネル"></p><p>ここから、コンセプトがリンクされているものを調整したり、削除したりすることができます。以下の例では、コンセプトは現在アセットにリンクされていません。</p><p>アセットをリンクするには、[リンク] <img src="'+c+'" alt="リンクボタン">ボタンをクリックします。</p><p>すると、アップロードしたコンセプトにリンク可能なすべての<strong>アセット</strong>が表示されます。</p><p><img src="'+_+'" alt="コンセプトリンク"></p><p>リンクしたいアセットをリストから選択します。すると、リンクされたアセット名が画面の上部に表示され、コンセプトのサムネイルの下にも表示されます。</p><p><img src="'+l+'" alt="コンセプトアセットのリンク"></p><p>コンセプトがアセットにリンクされると、アセットの詳細ページから参照できるようになります。アセットページに戻り、コンセプトにリンクしたアセットをクリックします。</p><p><img src="'+m+'" alt="アセット詳細ページ"></p><p>デフォルトでは、画面の2番目の部分にキャスティングの詳細が表示されます。ドロップダウンメニューを使用して、コンセプトを選択します。</p><p><img src="'+d+'" alt="アセット詳細コンセプト"></p><p>コンセプトセクションに入ると、このアセット用に作成されたすべてのコンセプトが表示されます。ステータス別にフィルタリングすることもできます。</p><p><img src="'+h+'" alt="アセット詳細コンセプトリスト"></p><h2 id="プレビューをバージョンとして公開" tabindex="-1">プレビューをバージョンとして公開 <a class="header-anchor" href="#プレビューをバージョンとして公開" aria-label="Permalink to “プレビューをバージョンとして公開”">​</a></h2><p>プレビュー、画像、または動画を公開するには、タスクのコメントパネルにアクセスし、<strong>[公開リビジョン]</strong>タブを選択します。</p><p>WFA<strong>ステータスなど、</strong>[フィードバックリクエスト]<strong>オプション付きのステータスを使用している場合、Kitsuは自動的に</strong>[公開リビジョン]**タブに切り替わります。</p><p><img src="'+f+'" alt="公開リビジョン"></p><p>任意のコメントに1つまたは複数のプレビューを追加することができます。 これらは、画像（<code>.png</code>、<code>.jpg</code>、<code>.jpeg</code>、<code>.gif</code>）、ビデオ（<code>.mp4</code>、<code>.mov</code>、<code>.wmv</code>）、または<code>.glb</code>ファイルです。 さらに、ブラウザからすべてのプレビューを確認したり、すべてを混ぜ合わせたりすることができます。</p><p>また、<code>.glb</code>ファイルをワイヤーフレームとして確認したり、<code>.HDR</code>ファイルを追加して照明を確認することもできます。詳細は<strong>カスタマイズ</strong>セクションを参照してください。</p><p><a href="./../configure-kitsu/#_3d-backgrounds">パイプラインのカスタマイズ</a>.</p><p>pdf、.zip、.rar、.ma、.mbなどの他のファイルはブラウザで表示できないため、確認するにはダウンロードする必要があります。</p><p>次に、<strong>[プレビューリビジョンを追加して公開]</strong>ボタンをクリックします。エクスプローラーが開き、ファイルまたは複数のファイルを選択できるようになります。</p><p><img src="'+b+'" alt="プレビューの添付"></p><p>また、ダウンロードせずに、クリップボードからこのアップロードダイアログに<strong>スクリーンショットをコピー＆ペースト</strong>することもできます。ファイルを選択すると、<strong>「公開するファイルを追加」</strong>ボタンの近くにファイル名が表示されます。</p><p><img src="'+j+'" alt="プレビューの添付（記入済み）"></p><p>また、アップロードしたいファイルをコメントセクションにドラッグ＆ドロップすると、自動的にアップロードプロセスが開始されます。</p><p><img src="'+u+'" alt="アタッチプレビューのドラッグ＆ドロップ"></p><p>プレビューの上に<strong>コメントを追加</strong>することができます。<strong>コメントを残す</strong>ボタンをクリックして、コメントセクションを開きます。</p><p><img src="'+x+'" alt="公開にコメントを追加する"></p><p>次に、ステータスを選択し、<strong>[投稿]</strong> ボタンでプレビューを公開します。</p><p>サムネイルとして公開を使用する方法の詳細については、<a href="./../thumbnails/">サムネイルに関するこのセクションを参照してください</a>。</p><h2 id="プレビューをバージョンにまとめる" tabindex="-1">プレビューをバージョンにまとめる <a class="header-anchor" href="#プレビューをバージョンにまとめる" aria-label="Permalink to “プレビューをバージョンにまとめる”">​</a></h2><p>複数の画像を同時に追加することも、画像をアップロードした後に別の画像を追加することもできます。</p><p><img src="'+k+'" alt="複数の画像のアップロード"></p><p><strong>プレビューの追加</strong>ポップアップでは、ファイルの選択を求められます。アップロードした画像をナビゲートできます。</p><p>番号をクリックしてドラッグ＆ドロップすることで、プレビューの順序を変更できます。</p><p><img src="'+P+'" alt="プレビューのドラッグ＆ドロップ"></p><p>プレビューを削除するには、コメントパネルを拡大し、バージョンの番号をクリックしてから、<img src="'+T+'" alt="削除ボタン">をクリックします。</p><p><img src="'+S+'" alt="コメントセクションの拡大と削除"></p>',56)])])}const I=s($,[["render",v]]);export{E as __pageData,I as default};
